#!/usr/bin/env bash
# Generated by bun-server-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-server-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_SERVER_BENCH_SOLUTION_EOF'
import { randomUUID } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);

type Phase = "legacy_only" | "dual_write" | "backfilling" | "cutover" | "rolled_back";

type RecordRow = {
  id: string;
  legacy_value: number;
  normalized_value: number | null;
  write_version: number;
  backfill_version: number | null;
};

let phase: Phase = "legacy_only";
const records = new Map<string, RecordRow>();
let backfillComplete = false;

function allRowsBackfilled(): boolean {
  if (records.size === 0) return true;
  return [...records.values()].every(
    (row) => row.normalized_value !== null && row.backfill_version === row.write_version,
  );
}

function readValue(row: RecordRow): number {
  if (phase === "cutover") {
    return row.normalized_value ?? row.legacy_value;
  }
  if (row.normalized_value !== null && (phase === "dual_write" || phase === "backfilling")) {
    return row.normalized_value;
  }
  return row.legacy_value;
}

function writeRecord(row: RecordRow, legacyValue: number): void {
  row.legacy_value = legacyValue;
  row.write_version += 1;
  if (phase === "dual_write" || phase === "backfilling" || phase === "cutover") {
    row.normalized_value = legacyValue * 2;
  }
}

function publicRecord(row: RecordRow): object {
  return {
    id: row.id,
    value: readValue(row),
    legacy_value: row.legacy_value,
    normalized_value: row.normalized_value,
    write_version: row.write_version,
  };
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/migration/status") {
      return Response.json(
        {
          phase,
          backfill_complete: backfillComplete,
          record_count: records.size,
        },
        { status: 200 },
      );
    }

    if (request.method === "POST" && url.pathname === "/migration/start") {
      if (phase !== "legacy_only" && phase !== "rolled_back") {
        return Response.json({ error: "invalid_phase" }, { status: 409 });
      }
      phase = "dual_write";
      backfillComplete = false;
      for (const row of records.values()) {
        row.normalized_value = row.legacy_value * 2;
      }
      return Response.json({ phase }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/migration/backfill") {
      if (phase !== "dual_write" && phase !== "backfilling") {
        return Response.json({ error: "invalid_phase" }, { status: 409 });
      }
      phase = "backfilling";
      const batch = Number(url.searchParams.get("batch") ?? "10");
      const limit = Number.isInteger(batch) && batch > 0 ? batch : 10;
      const rows = [...records.values()].sort((a, b) => a.id.localeCompare(b.id));
      let processed = 0;
      let skipped = 0;

      for (const row of rows) {
        if (processed >= limit) break;
        if (row.normalized_value !== null && row.backfill_version === row.write_version) {
          skipped += 1;
          continue;
        }
        const snapshotVersion = row.write_version;
        row.normalized_value = row.legacy_value * 2;
        if (row.write_version !== snapshotVersion) {
          skipped += 1;
          continue;
        }
        row.backfill_version = row.write_version;
        processed += 1;
      }

      backfillComplete = allRowsBackfilled();

      return Response.json({ processed, skipped, backfill_complete: backfillComplete }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/migration/cutover") {
      if (phase !== "backfilling" || !backfillComplete) {
        return Response.json({ error: "backfill_incomplete" }, { status: 409 });
      }
      phase = "cutover";
      return Response.json({ phase }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/migration/rollback") {
      if (phase === "legacy_only" || phase === "rolled_back") {
        return Response.json({ error: "invalid_phase" }, { status: 409 });
      }
      phase = "rolled_back";
      backfillComplete = false;
      for (const row of records.values()) {
        row.normalized_value = null;
        row.backfill_version = null;
      }
      return Response.json({ phase }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/records") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || !Number.isInteger(record.legacy_value)) {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const row: RecordRow = {
        id: randomUUID(),
        legacy_value: record.legacy_value as number,
        normalized_value: phase === "legacy_only" || phase === "rolled_back" ? null : (record.legacy_value as number) * 2,
        write_version: 1,
        backfill_version: null,
      };
      records.set(row.id, row);
      return Response.json(publicRecord(row), { status: 201 });
    }

    const recordMatch = /^\/records\/([^/]+)$/.exec(url.pathname);
    if (recordMatch) {
      const id = decodeURIComponent(recordMatch[1]!);
      const row = records.get(id);
      if (!row) {
        return Response.json({ error: "not_found" }, { status: 404 });
      }

      if (request.method === "GET") {
        return Response.json(publicRecord(row), { status: 200 });
      }

      if (request.method === "PATCH") {
        let body: unknown;
        try {
          body = await request.json();
        } catch {
          return Response.json({ error: "invalid_body" }, { status: 422 });
        }
        const record = body as Record<string, unknown> | null;
        if (!record || !Number.isInteger(record.legacy_value)) {
          return Response.json({ error: "invalid_body" }, { status: 422 });
        }
        writeRecord(row, record.legacy_value as number);
        return Response.json(publicRecord(row), { status: 200 });
      }
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`online-migration-backfill reference listening on ${port}`);
BUN_SERVER_BENCH_SOLUTION_EOF
